package entity.seat;import java.time.LocalDateTime;// 座位类型枚举（与影厅VIP/普通座对应）enum SeatType {    VIP("VIP座"),    REGULAR("普通座");    private final String typeDesc;    SeatType(String typeDesc) {        this.typeDesc = typeDesc;    }    public String getTypeDesc() {        return typeDesc;    }}// 座位状态枚举（与购票流程锁定/售出/空闲逻辑对应）enum SeatStatus {    FREE("空闲"),    // 可锁定    LOCKED("已锁定"),// 已下单未支付（有过期时间）    SOLD("已售出");  // 已支付    private final String statusDesc;    SeatStatus(String statusDesc) {        this.statusDesc = statusDesc;    }    public String getStatusDesc() {        return statusDesc;    }}public class Seat {    private String seatId;          // 座位唯一ID（如HALL01_1_2，对应1号厅1排2座）    private double price;           // 座位票价（与场次的普通/VIP价关联）    private String hallId;          // 所属影厅ID（关联Hall类）    private String sessionId;       // 关联场次ID（关键！锁定座位针对具体场次）    private SeatType type;          // 座位类型（VIP/普通）    private SeatStatus status = SeatStatus.FREE; // 默认空闲    private String lockedByUserId;  // 锁定用户ID（关联User）    private LocalDateTime lockedExpireTime; // 锁定过期时间（默认15分钟，与购票流程一致）    /**     * 构造方法：创建座位时绑定核心信息（与Hall、Session关联）     * @param seatId 座位ID（如HALL01_1_2）     * @param hallId 所属影厅ID（如HALL01）     * @param type 座位类型（VIP/普通）     * @param sessionId 关联场次ID（如SESS202512041900）     * @param basePrice 基础票价（从Session的regularPrice/vipPrice传入）     */    public Seat(String seatId, String hallId, SeatType type, String sessionId, double basePrice) {        this.seatId = seatId;        this.hallId = hallId;        this.type = type;        this.sessionId = sessionId;        this.price = basePrice; // 直接复用场次的基础票价，无需复杂计算    }    /**     * 锁定座位（核心方法：与购票流程的"锁定座位"步骤对应）     * @param userId 锁定用户ID     * @param expireMinutes 锁定过期分钟数（默认15分钟）     * @return 锁定是否成功（仅空闲座位可锁定）     */    public boolean lockSeat(String userId, int expireMinutes) {        // 只有"空闲"状态的座位才能锁定        if (this.status != SeatStatus.FREE) {            return false;        }        // 设置锁定信息        this.lockedByUserId = userId;        this.lockedExpireTime = LocalDateTime.now().plusMinutes(expireMinutes);        this.status = SeatStatus.LOCKED;        return true;    }    /**     * 解锁座位（核心方法：支付失败/超时/取消订单时调用）     */    public void unlockSeat() {        this.status = SeatStatus.FREE; // 状态回归空闲        this.lockedByUserId = null;    // 清空锁定用户        this.lockedExpireTime = null;  // 清空过期时间    }    /**     * 标记座位为已售出（支付成功后调用）     */    public void markAsSold() {        if (this.status == SeatStatus.LOCKED) { // 仅锁定状态可转为售出            this.status = SeatStatus.SOLD;            this.lockedByUserId = null;            this.lockedExpireTime = null;        }    }    /**     * 校验锁定是否过期（系统定时调用，清理过期锁定）     * @return true=已过期，false=未过期     */    public boolean isLockExpired() {        return this.status == SeatStatus.LOCKED                && LocalDateTime.now().isAfter(this.lockedExpireTime);    }    // ---------------------- 简单getter/setter（适配系统调用）----------------------    public String getSeatId() {        return seatId;    }    public double getPrice() {        return price;    }    public void setPrice(double price) {        this.price = price; // 支持后续调整票价（如场次调价）    }    public String getHallId() {        return hallId;    }    public String getSessionId() {        return sessionId;    }    public SeatType getType() {        return type;    }    public SeatStatus getStatus() {        return status;    }    public String getLockedByUserId() {        return lockedByUserId;    }    public LocalDateTime getLockedExpireTime() {        return lockedExpireTime;    }}